   160|    return { ok: true, accessToken, refreshToken, expiresAt };
   161|  } catch (error) {
   162|    return { ok: false, errorMessage: error instanceof Error ? error.message : 'Network failure during password grant.' };
   163|  } finally {
   164|    clearTimeout(timer);
